import{_ as t,o as r,c as e,a2 as o}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"黃金追蹤日誌 — 2026-06-16（TST 05:00）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃金研究/追蹤日誌/黃金追蹤_2026-06-16.md","filePath":"Deep32Q知識庫/產業洞察/黃金研究/追蹤日誌/黃金追蹤_2026-06-16.md"}'),i={name:"Deep32Q知識庫/產業洞察/黃金研究/追蹤日誌/黃金追蹤_2026-06-16.md"};function h(d,a,l,n,s,b){return r(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="黃金追蹤日誌-—-2026-06-16-tst-05-00" tabindex="-1">黃金追蹤日誌 — 2026-06-16（TST 05:00） <a class="header-anchor" href="#黃金追蹤日誌-—-2026-06-16-tst-05-00" aria-label="Permalink to &quot;黃金追蹤日誌 — 2026-06-16（TST 05:00）&quot;">​</a></h1><h2 id="本日敘事錨點" tabindex="-1">本日敘事錨點 <a class="header-anchor" href="#本日敘事錨點" aria-label="Permalink to &quot;本日敘事錨點&quot;">​</a></h2><p><strong>核心事件：荷莫茲海峽重開預期壓低油價，黃金反而走強。</strong></p><p>今天的黃金行情有點反直覺：股市大漲、風險偏好回升、油價大跌，照理說對黃金不利。但黃金仍然走強，原因在於市場把荷莫茲重開解讀為「能源通膨壓力降溫」，進而壓低了升息預期與美元。</p><p>也就是說，今天黃金不是在反映「避險恐慌」，而是在反映：</p><ol><li>油價下跌 → 通膨壓力下降</li><li>升息預期降溫 → 持有黃金的機會成本下降</li><li>美元走弱 → 以美元計價的黃金更便宜</li></ol><p>所以今天最關鍵的判斷是：<strong>黃金不是因為「世界更危險」而漲，而是因為「利率與通膨預期變得更有利」而漲。</strong></p><p>查詢時間：2026-06-16 05:00 TST。</p><hr><h2 id="_10-項追蹤指標檢查" tabindex="-1">10 項追蹤指標檢查 <a class="header-anchor" href="#_10-項追蹤指標檢查" aria-label="Permalink to &quot;10 項追蹤指標檢查&quot;">​</a></h2><h3 id="_1-comex-黃金現貨價格" tabindex="-1">1. COMEX 黃金現貨價格 <a class="header-anchor" href="#_1-comex-黃金現貨價格" aria-label="Permalink to &quot;1. COMEX 黃金現貨價格&quot;">​</a></h3><p>現貨黃金約 <strong>4,336 美元/盎司</strong>，為近一週高點。<br> 市場主因是荷莫茲重開預期壓低油價，降低升息風險與美元，推升黃金。<br> 來源：Kitco/Reuters (2026-06-15)</p><h3 id="_2-美國-10-年期-tips-實質利率" tabindex="-1">2. 美國 10 年期 TIPS 實質利率 <a class="header-anchor" href="#_2-美國-10-年期-tips-實質利率" aria-label="Permalink to &quot;2. 美國 10 年期 TIPS 實質利率&quot;">​</a></h3><p>本日未取得最新即時讀數，但從「公債殖利率下滑 + 黃金走強」的組合來看，市場傾向解讀為實質利率壓力暫時減弱。<br> 查詢時間：2026-06-16 05:00 TST。</p><h3 id="_3-美元指數-dxy" tabindex="-1">3. 美元指數 DXY <a class="header-anchor" href="#_3-美元指數-dxy" aria-label="Permalink to &quot;3. 美元指數 DXY&quot;">​</a></h3><p>美元回落至約 <strong>99.4–99.7</strong> 區間，為 10 日低檔。<br> 美元走弱對黃金形成直接支撐。<br> 來源：Kitco/Reuters (2026-06-15)、Yahoo Finance (2026-06-15)</p><h3 id="_4-聯準會利率決策-點陣圖" tabindex="-1">4. 聯準會利率決策 + 點陣圖 <a class="header-anchor" href="#_4-聯準會利率決策-點陣圖" aria-label="Permalink to &quot;4. 聯準會利率決策 + 點陣圖&quot;">​</a></h3><p>市場普遍預期本週 FOMC 維持利率不變。<br> 關鍵在 Warsh 的首次主持與政策語氣，這將決定黃金後續是「利多延續」還是「短線利多出盡」。<br> 來源：USA Today (2026-06-15)、The Guardian (2026-06-15)、CNBC (2026-06-15)</p><h3 id="_5-央行購金數據-wgc-季報" tabindex="-1">5. 央行購金數據（WGC 季報） <a class="header-anchor" href="#_5-央行購金數據-wgc-季報" aria-label="Permalink to &quot;5. 央行購金數據（WGC 季報）&quot;">​</a></h3><p>本日無新官方數據，但近期媒體仍持續提及央行購金結構是支撐中長期金價的重要因素。<br> 今日僅標記「結構性支撐仍在」，不作誇大。<br> 來源：Kitco/Reuters (2026-06-15)、J Rotbart (2026-06-15)</p><h3 id="_6-地緣風險事件" tabindex="-1">6. 地緣風險事件 <a class="header-anchor" href="#_6-地緣風險事件" aria-label="Permalink to &quot;6. 地緣風險事件&quot;">​</a></h3><p>美伊框架協議是本日最大事件。<br> 但因為協議尚未完全簽署，加上核能與制裁細節仍待談判，黃金的「地緣保鑣價值」仍未完全退場。<br> 來源：CNBC (2026-06-15)、Kitco/Reuters (2026-06-15)</p><h3 id="_7-通膨數據-cpi、pce" tabindex="-1">7. 通膨數據（CPI、PCE） <a class="header-anchor" href="#_7-通膨數據-cpi、pce" aria-label="Permalink to &quot;7. 通膨數據（CPI、PCE）&quot;">​</a></h3><p>今天金價上漲的邏輯之一，就是市場預期油價回落會壓縮未來通膨壓力。<br> 但目前通膨水準仍偏高，代表黃金的支撐並非「通膨已解決」，而是「通膨風險預期正在調整」。<br> 來源：USA Today (2026-06-15)、Kitco (2026-06-15)</p><h3 id="_8-黃金-etf-持倉量" tabindex="-1">8. 黃金 ETF 持倉量 <a class="header-anchor" href="#_8-黃金-etf-持倉量" aria-label="Permalink to &quot;8. 黃金 ETF 持倉量&quot;">​</a></h3><p>今日未取得即時 ETF 持倉更新。<br> 目前先以價格與宏觀數據判斷為主。<br> 查詢時間：2026-06-16 05:00 TST。</p><h3 id="_9-黃金礦產供應" tabindex="-1">9. 黃金礦產供應 <a class="header-anchor" href="#_9-黃金礦產供應" aria-label="Permalink to &quot;9. 黃金礦產供應&quot;">​</a></h3><p>今日無重大新聞。<br> 供給端不是本日驅動因子。<br> 查詢時間：2026-06-16 05:00 TST。</p><h3 id="_10-大型投行金價預測" tabindex="-1">10. 大型投行金價預測 <a class="header-anchor" href="#_10-大型投行金價預測" aria-label="Permalink to &quot;10. 大型投行金價預測&quot;">​</a></h3><p>花旗上調短期金價預測至 <strong>4,500 美元</strong>，並維持中期 <strong>5,000 美元</strong> 看法。<br> 這代表即使停火利好，部分投行仍認為金價中期具結構性支撐。<br> 來源：Kitco/Reuters (2026-06-15)</p><hr><h2 id="有什麼變化" tabindex="-1">有什麼變化？ <a class="header-anchor" href="#有什麼變化" aria-label="Permalink to &quot;有什麼變化？&quot;">​</a></h2><h3 id="變化一-油價回落壓低升息預期-黃金獲得新的利多邏輯" tabindex="-1">變化一：油價回落壓低升息預期，黃金獲得新的利多邏輯 <a class="header-anchor" href="#變化一-油價回落壓低升息預期-黃金獲得新的利多邏輯" aria-label="Permalink to &quot;變化一：油價回落壓低升息預期，黃金獲得新的利多邏輯&quot;">​</a></h3><p>變化內容：荷莫茲重開預期帶動原油大跌。<br> 為什麼：市場認為能源通膨壓力可能減弱。<br> 影響：升息預期降溫，美元與實質利率預期同步受壓，有利黃金。<br> 關鍵節點：本週 FOMC 語氣。<br> 來源：Kitco/Reuters (2026-06-15)、CNBC (2026-06-15)</p><h3 id="變化二-黃金在-risk-on-環境下仍漲-代表多因素支撐" tabindex="-1">變化二：黃金在 risk-on 環境下仍漲，代表多因素支撐 <a class="header-anchor" href="#變化二-黃金在-risk-on-環境下仍漲-代表多因素支撐" aria-label="Permalink to &quot;變化二：黃金在 risk-on 環境下仍漲，代表多因素支撐&quot;">​</a></h3><p>變化內容：股市大漲，但黃金未跌。<br> 為什麼：美元走弱、利率預期調整、停火細節未完全落地。<br> 影響：黃金從「單一避險資產」切換成「利率+匯率+地緣混合資產」。<br> 關鍵節點：美元與 FOMC。<br> 來源：Kitco/Reuters (2026-06-15)</p><hr><h2 id="投行預測彙整" tabindex="-1">投行預測彙整 <a class="header-anchor" href="#投行預測彙整" aria-label="Permalink to &quot;投行預測彙整&quot;">​</a></h2><table tabindex="0"><thead><tr><th>投行/來源</th><th>短期展望</th><th>中期展望</th><th>今日判斷</th></tr></thead><tbody><tr><td>Kitco NewsWire / 技術面</td><td>支撐 4,280–4,240，阻力 4,364–4,400</td><td>若站穩 4,400，可挑戰 4,460–4,575</td><td>偏多震盪</td></tr><tr><td>UBS</td><td>短線可能整理</td><td>等待本週 Fed</td><td>中性偏多</td></tr><tr><td>Barclays</td><td>仍看好</td><td>中期支撐仍在</td><td>偏多</td></tr><tr><td>Citi</td><td>上調至 4,500</td><td>維持 5,000</td><td>偏多</td></tr></tbody></table><hr><h2 id="延續昨日敘事" tabindex="-1">延續昨日敘事 <a class="header-anchor" href="#延續昨日敘事" aria-label="Permalink to &quot;延續昨日敘事&quot;">​</a></h2><p>昨日報告指出：若荷莫茲重開預期升溫，市場會開始從「戰爭避險」轉向「利率與通膨重定價」。<br> 今天已驗證這個轉向：油價下跌、美元走弱、升息預期下降，黃金因此獲得利多。</p><p>下一階段重點已不是「是否停火」，而是：</p><ol><li>本週 FOMC 對通膨與利率的表態</li><li>美元是否續弱</li><li>停火細節是否再次生變</li></ol><p>查詢時間：2026-06-16 05:00 TST。</p>',45)])])}const _=t(i,[["render",h]]);export{p as __pageData,_ as default};
